-- supabase/seed/demo_businesses.sql
-- Export de l'état prod nettoyé au 04/07/2026 : 1078 établissements démo
-- (slug LIKE 'demo-' + catégorie + ville + index), 2 par couple city×category après
-- nettoyage. Tous avec horaires 09:00-19:00 lun-sam (open_days = [1..6]).
-- Remplace l'ancienne version générée programmatiquement (non idempotente).
--
-- Idempotent : le WHERE NOT EXISTS empêche toute double insertion si rejoué.
-- Nettoyage : DELETE FROM businesses WHERE slug LIKE 'demo-%';

